#!/usr/bin/env bash
set -euo pipefail

VERSION="6.2.0"
PAYLOAD_SHA256="93a8002fbdcff20340848a2bb56b3d82154926db325efe3f2a2e0ed0e679aaae"
DO_SWITCH=0
DO_SYSTEMD=0

usage() {
  cat <<'EOF'
BTC Quant v6.2 Unified installer

Usage:
  bash apply_v62_unified_quant.sh
  bash apply_v62_unified_quant.sh --switch
  bash apply_v62_unified_quant.sh --switch --systemd

Default installs and self-tests only. --switch stops v4.1/v4.2/v6.0/v6.1
legacy loops and starts the single v6.2 screen loop. --systemd converts v6.2
from screen to a boot-persistent systemd service after the switch.
EOF
}

for arg in "$@"; do
  case "$arg" in
    --switch) DO_SWITCH=1 ;;
    --systemd) DO_SYSTEMD=1; DO_SWITCH=1 ;;
    -h|--help) usage; exit 0 ;;
    *) echo "Unknown argument: $arg"; usage; exit 2 ;;
  esac
done

ROOT="$(pwd)"
STAMP="$(date +%Y%m%d_%H%M%S)"
BACKUP_DIR="$ROOT/local_backups/v62_install_$STAMP"
TMP_DIR="$(mktemp -d)"
PAYLOAD_FILE="$TMP_DIR/v62_payload.tar.gz"
EXTRACT_DIR="$TMP_DIR/payload"
mkdir -p "$EXTRACT_DIR"
trap 'rm -rf "$TMP_DIR"' EXIT

if [[ ! -d "$ROOT/index_sniper" ]]; then
  echo "❌ index_sniper 폴더가 없습니다. ~/index-sniper-pro 루트에서 실행하세요."
  exit 1
fi
for required in   index_sniper/exchange/bitget_uta.py   index_sniper/strategy/indicators.py   index_sniper/telegram/bot.py; do
  if [[ ! -f "$ROOT/$required" ]]; then
    echo "❌ 필수 기존 모듈 없음: $required"
    exit 1
  fi
done
if pgrep -af 'python(3)? .*index_sniper[.]unified_v62 loop' >/dev/null 2>&1; then
  echo "❌ 기존 v6.2 loop가 실행 중입니다. 먼저 bash stop_v62_unified.sh 를 실행하세요."
  pgrep -af 'python(3)? .*index_sniper[.]unified_v62 loop' || true
  exit 1
fi

PYTHON_BIN="$ROOT/.venv/bin/python"
[[ -x "$PYTHON_BIN" ]] || PYTHON_BIN="$(command -v python3)"
"$PYTHON_BIN" - <<'PYVER'
import sys
if sys.version_info < (3, 10):
    raise SystemExit(f"Python 3.10+ required, found {sys.version.split()[0]}")
print("Python:", sys.version.split()[0])
PYVER

cat > "$TMP_DIR/payload.b64" <<'PAYLOAD_B64'

PAYLOAD_B64
base64 -d "$TMP_DIR/payload.b64" > "$PAYLOAD_FILE"
ACTUAL_SHA="$(sha256sum "$PAYLOAD_FILE" | awk '{print $1}')"
if [[ "$ACTUAL_SHA" != "$PAYLOAD_SHA256" ]]; then
  echo "❌ payload checksum mismatch: $ACTUAL_SHA"
  exit 1
fi

tar -xzf "$PAYLOAD_FILE" -C "$EXTRACT_DIR"

# Validate every embedded file before touching the project.
EXTRACT_DIR_ENV="$EXTRACT_DIR" "$PYTHON_BIN" - <<'PYVERIFY'
from pathlib import Path
import hashlib, json, os
root = Path(os.environ["EXTRACT_DIR_ENV"])
manifest = json.loads((root / "V62_MANIFEST.json").read_text(encoding="utf-8"))
assert manifest["version"] == "6.2.0"
assert manifest["paper_only"] is True
for item in manifest["files"]:
    p = root / item["path"]
    if not p.is_file():
        raise SystemExit(f"payload missing: {item['path']}")
    data = p.read_bytes()
    if len(data) != item["size"]:
        raise SystemExit(f"payload size mismatch: {item['path']}")
    if hashlib.sha256(data).hexdigest() != item["sha256"]:
        raise SystemExit(f"payload hash mismatch: {item['path']}")
print(f"Payload verified: {len(manifest['files'])} files")
PYVERIFY

mkdir -p "$BACKUP_DIR"
ROOT_ENV="$ROOT" EXTRACT_DIR_ENV="$EXTRACT_DIR" BACKUP_ENV="$BACKUP_DIR" "$PYTHON_BIN" - <<'PYBACKUP'
from pathlib import Path
import json, os, shutil
root = Path(os.environ["ROOT_ENV"])
source = Path(os.environ["EXTRACT_DIR_ENV"])
backup = Path(os.environ["BACKUP_ENV"])
manifest = json.loads((source / "V62_MANIFEST.json").read_text(encoding="utf-8"))
paths = [item["path"] for item in manifest["files"]] + ["V62_MANIFEST.json", ".env"]
created = []
for rel in paths:
    src = root / rel
    if src.exists() and src.is_file():
        dst = backup / rel
        dst.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(src, dst)
    elif rel not in {".env"}:
        created.append(rel)
(backup / "created_files.json").write_text(json.dumps(created, indent=2), encoding="utf-8")
print("Backup:", backup)
PYBACKUP

restore_on_failure() {
  echo "⚠️ 설치 검증 실패 — 대상 파일을 설치 전 상태로 복구합니다."
  ROOT_ENV="$ROOT" BACKUP_ENV="$BACKUP_DIR" EXTRACT_DIR_ENV="$EXTRACT_DIR" "$PYTHON_BIN" - <<'PYRESTORE'
from pathlib import Path
import json, os, shutil
root=Path(os.environ["ROOT_ENV"])
backup=Path(os.environ["BACKUP_ENV"])
source=Path(os.environ["EXTRACT_DIR_ENV"])
manifest=json.loads((source/"V62_MANIFEST.json").read_text(encoding="utf-8"))
for rel in [item["path"] for item in manifest["files"]] + ["V62_MANIFEST.json"]:
    old=backup/rel
    target=root/rel
    if old.exists():
        target.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(old,target)
    elif target.exists():
        target.unlink()
env_old=backup/".env"
if env_old.exists():
    shutil.copy2(env_old,root/".env")
PYRESTORE
}

# Install files. The package __init__.py is intentionally not replaced.
cp -a "$EXTRACT_DIR/." "$ROOT/"
chmod +x "$ROOT"/run_v62_once.sh   "$ROOT"/start_v62_unified.sh   "$ROOT"/stop_v62_unified.sh   "$ROOT"/status_v62_unified.sh   "$ROOT"/switch_to_v62_unified.sh   "$ROOT"/rollback_v62_unified.sh   "$ROOT"/report_v62_unified.sh   "$ROOT"/doctor_v62_unified.sh   "$ROOT"/view_v62_log.sh   "$ROOT"/install_v62_systemd.sh
mkdir -p "$ROOT/data/v62_unified" "$ROOT/data/event_risk_pro" "$ROOT/logs" "$ROOT/config"

# Safe line-based .env update. Never source .env, so symbols such as ^GSPC
# and ^NDX cannot be interpreted as shell commands.
ROOT_ENV="$ROOT" "$PYTHON_BIN" - <<'PYENV'
from pathlib import Path
import os, re
root=Path(os.environ["ROOT_ENV"])
p=root/".env"
lines=p.read_text(encoding="utf-8",errors="ignore").splitlines() if p.exists() else []
values={
    "V62_CONFIG":"config/v62_unified.json",
    "V62_NOTIFY":"true",
    "V62_NOTIFY_HEARTBEAT":"true",
    "V62_HEARTBEAT_MINUTES":"60",
    "V62_LOOP_SECONDS":"300",
    "V62_EVENT_ENABLED":"true",
    "V62_EVENT_COLLECT_INTERVAL_SECONDS":"900",
    "V62_PAPER_ENABLED":"true",
}
keys=set(values)
out=[]
for line in lines:
    m=re.match(r"^([A-Za-z_][A-Za-z0-9_]*)=",line.strip())
    if m and m.group(1) in keys:
        continue
    out.append(line)
if out and out[-1].strip():
    out.append("")
out.append("# BTC Quant v6.2 Unified — paper only")
for key,value in values.items():
    out.append(f'{key}="{value}"')
p.write_text("\n".join(out)+"\n",encoding="utf-8")
try:
    p.chmod(0o600)
except Exception:
    pass
print(".env v6.2 keys updated without shell sourcing")
PYENV

# Verify installed files and compile all v6.2 modules.
if ! ROOT_ENV="$ROOT" "$PYTHON_BIN" - <<'PYINSTALLED'
from pathlib import Path
import hashlib,json,os,py_compile
root=Path(os.environ["ROOT_ENV"])
m=json.loads((root/"V62_MANIFEST.json").read_text(encoding="utf-8"))
for item in m["files"]:
    p=root/item["path"]
    if hashlib.sha256(p.read_bytes()).hexdigest()!=item["sha256"]:
        raise SystemExit(f"installed checksum mismatch: {item['path']}")
for rel in (
    "index_sniper/event_raw_collector_v62_compat.py",
    "index_sniper/event_risk_v62.py",
    "index_sniper/unified_v62.py",
):
    py_compile.compile(str(root/rel),doraise=True)
print("Installed checksums and bytecode compile: OK")
PYINSTALLED
then
  restore_on_failure
  exit 1
fi

if ! PYTHONPATH="$ROOT" "$PYTHON_BIN" -m index_sniper.unified_v62 self-test; then
  restore_on_failure
  exit 1
fi

ROOT_ENV="$ROOT" BACKUP_ENV="$BACKUP_DIR" PAYLOAD_SHA_ENV="$PAYLOAD_SHA256" "$PYTHON_BIN" - <<'PYRECORD'
from pathlib import Path
import datetime as dt,json,os
root=Path(os.environ["ROOT_ENV"])
record={
  "version":"6.2.0",
  "paper_only":True,
  "installed_utc":dt.datetime.now(dt.timezone.utc).isoformat(),
  "payload_sha256":os.environ["PAYLOAD_SHA_ENV"],
  "backup_dir":os.environ["BACKUP_ENV"],
}
out=root/"data/v62_unified"/f"install_{dt.datetime.now().strftime('%Y%m%d_%H%M%S')}.json"
out.write_text(json.dumps(record,ensure_ascii=False,indent=2)+"\n",encoding="utf-8")
print("Install record:",out)
PYRECORD

echo
echo "✅ BTC Quant v6.2 Unified + Event Risk v6.2 설치 완료"
echo "버전: $VERSION / paper only"
echo "백업: $BACKUP_DIR"
echo
echo "권장 순서:"
echo "  bash doctor_v62_unified.sh"
echo "  bash switch_to_v62_unified.sh"
echo "  bash status_v62_unified.sh"
echo "  bash view_v62_log.sh"
echo
echo "통합 후에는 v4.1/v4.2/v6.0/v6.1 별도 loop를 같이 켜지 않습니다."

if [[ "$DO_SWITCH" -eq 1 ]]; then
  echo
  echo "🔎 network doctor 실행..."
  bash "$ROOT/doctor_v62_unified.sh"
  echo
  echo "🔄 legacy 알람 중지 후 v6.2 통합 전환..."
  bash "$ROOT/switch_to_v62_unified.sh"
fi
if [[ "$DO_SYSTEMD" -eq 1 ]]; then
  echo
  echo "⚙️ systemd 전환..."
  bash "$ROOT/install_v62_systemd.sh"
fi
